package gen_day2;

public class If_else_ladder {
	public static void main(String[] args) {
		int examscore = 75;
		char grade; 
	// TODO Auto-generated method stub
if(examscore >= 90)
{
	grade='A';
}else if(examscore>=80)
{
	grade='B';
}else
{
	grade='c';
}
	System.out.println("grade is"+grade);
	}

}
